900   PointerMayBeCaptured(Alloca, &Tracker);
901   if (Tracker.Captured)
902     return false;
903 
904   bool Changed = false;
905   for (auto [ICmp, Operands] : Tracker.ICmps) {
906     switch (Operands) {
907     case 1:
908     case 2: {
