972   // (X+ -1) >s X      --> X <s (MAXSINT-(-1-1))      --> X == -128
973 
974   assert(Pred == ICmpInst::ICMP_SGT || Pred == ICmpInst::ICMP_SGE);
975   return new ICmpInst(ICmpInst::ICMP_SLT, X,
976                       ConstantInt::get(X->getType(), SMax - (C - 1)));
